import React, { useState, useMemo, useEffect } from "react";
import { useFeatures } from "./hooks/useFeature";
import FeatureCard from "./components/FeatureCard";
import FeatureCardAdmin from "./components/FeatureCard";
import FeatureModal from "./components/FeatureModal";
import FilterBar from "./components/FilterBar";
import StatsBar from "./components/StatsBar";
import EmptyState from "./components/EmptyState";
import { STATUSES } from "./utils/costants";

// ── Route helper (no router library needed) ──────────────────────────────────
function useIsAdmin() {
  const [isAdmin, setIsAdmin] = useState(
    window.location.pathname.startsWith("/admin")
  );
  useEffect(() => {
    // Support back/forward navigation
    const onPop = () => setIsAdmin(window.location.pathname.startsWith("/admin"));
    window.addEventListener("popstate", onPop);
    // Allow other code to call window.setAppRoute('admin') or window.setAppRoute('user')
    window.setAppRoute = (route) => {
      setIsAdmin(route === "admin");
    };
    return () => window.removeEventListener("popstate", onPop);
  }, []);
  return isAdmin;
}

export default function App() {
  const isAdmin = useIsAdmin();
  const { features, addFeature, updateFeature, deleteFeature, updateStatus } = useFeatures();
  const [filter, setFilter] = useState("All");
  const [modal, setModal] = useState(null); // null | "add" | feature-object

  const filtered = useMemo(() => {
    if (filter === "All") return features;
    return features.filter((f) => f.status === filter);
  }, [features, filter]);

  const counts = useMemo(() => {
    const c = {};
    STATUSES.forEach((s) => { c[s] = features.filter((f) => f.status === s).length; });
    return c;
  }, [features]);

  function handleSave(formData) {
    if (modal && modal.id) {
      updateFeature(modal.id, formData);
    } else {
      addFeature(formData);
    }
  }

  return (
    <div className="app app-layout">
      <aside className="sidebar-nav">
        <div className="sidebar-title">Feature Tracker</div>
        <FilterBar active={filter} onChange={setFilter} counts={counts} />
        <button
          className="btn btn-ghost sidebar-history"
          onClick={() => {
            window.history.pushState({}, "", "/history");
            window.setAppRoute && window.setAppRoute("history");
          }}
        >
          View All History
        </button>
      </aside>

      <main className="main-content">
        {/* ── Header ── */}
        <header className="app-header">
          <div className="header-left">
            <h1 className="app-title">Feature Tracker</h1>
            <p className="app-subtitle">
              {isAdmin
                ? "Track, prioritize, and ship great ideas"
                : "Browse and explore submitted feature requests"}
            </p>
          </div>

          {/* Only admins see the Add Feature button */}
          {isAdmin && (
            <button
              className="btn btn-primary"
              style={{ minWidth: 120, fontWeight: 700, fontSize: 18 }}
              onClick={() => setModal("add")}
            >
              + Add Feature
            </button>
          )}
        </header>

        {/* ── Stats ── */}
        <StatsBar features={features} />

        {/* ── Cards ── */}
        {filtered.length === 0 ? (
          <EmptyState
            filter={filter}
            onAdd={isAdmin ? () => setModal("add") : undefined}
          />
        ) : (
          <div className="cards-grid">
            {filtered.map((f) =>
              isAdmin ? (
                // Admin card — edit / delete / status change + image lightbox
                <FeatureCardAdmin
                  key={f.id}
                  feature={f}
                  onEdit={(feat) => setModal(feat)}
                  onDelete={deleteFeature}
                  onStatusChange={updateStatus}
                />
              ) : (
                // User card — view details + image lightbox only
                <FeatureCard
                  key={f.id}
                  feature={f}
                  onViewDetails={() => {}}
                />
              )
            )}
          </div>
        )}

        {/* ── Modal (admin only) ── */}
        {isAdmin && modal !== null && (
          <FeatureModal
            feature={modal === "add" ? null : modal}
            onSave={handleSave}
            onClose={() => setModal(null)}
          />
        )}
      </main>
    </div>
  );
}
